create table public.tenants (  id uuid primary key default gen_random_uuid(),  name text not null,  slug text unique not null,  plan_code text,  locale text default 'pt-BR',  timezone text default 'America/Sao_Paulo',  status text not null default 'active' check (status in ('active','suspended','archived')),  created_at timestamptz not null default now());create table public.users (  id uuid primary key default gen_random_uuid(),  auth_user_id uuid unique,  name text,  email text unique not null,  created_at timestamptz not null default now());create table public.tenant_memberships (  id uuid primary key default gen_random_uuid(),  tenant_id uuid not null references public.tenants(id) on delete cascade,  user_id uuid not null references public.users(id) on delete cascade,  role text not null check (role in ('owner','admin','hr','analyst','manager','participant')),  status text not null default 'active' check (status in ('active','revoked')),  created_at timestamptz not null default now(),  unique (tenant_id, user_id));create index on public.tenant_memberships (user_id);create index on public.tenant_memberships (tenant_id, role);